package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.util.Months;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;

import java.util.Set;

@AllArgsConstructor
public class HeeftPatronaleVermindering707 {

    public static final LocalDateInterval ACTIVITEITS_PERIODE = new Months(2023, 1, 2023, 6);
    public static final LocalDateInterval ACTIVITEITS_PERIODE_OPTIONAL = new Months(2023, 7, 2023, 12);

    private static final Set<DmfapplWnkengetal> KENGETAL_IN_AANMERKING =
            ImmutableSet.of(DmfapplWnkengetal.MINDERVALIDE_HANDARBEIDERS, DmfapplWnkengetal.GEWONE_HANDARBEIDERS, DmfapplWnkengetal.CONTRACTUELE_HANDARBEIDERS_VERVANGERS,
                    DmfapplWnkengetal.GESUB_CONTRACTUELE_HANDARBEIDERS, DmfapplWnkengetal.LEERPLICHTIGE_GEWONE_HANDARBEIDERS, DmfapplWnkengetal.LEERLING_HANDARBEIDERS,
                    DmfapplWnkengetal.ANDERE_KUNSTENAARS, DmfapplWnkengetal.LEERPLICHTIGE_KUNSTENAARS,
                    DmfapplWnkengetal.HANDARBEIDER_VRIJSTELLING_PATRONALE_BIJDRAGE_DMFA, DmfapplWnkengetal.HOOFDARBEIDER_VRIJSTELLING_PATRONALE_BIJDRAGE_DMFA,
                    DmfapplWnkengetal.LOKALE_MANDATARIS_NIET_BECHERMD_DMFA, DmfapplWnkengetal.LEERLING_HOOFDARBEIDERS, DmfapplWnkengetal.CONTR_HOOFDARBEIDERS_VERVANGERS,
                    DmfapplWnkengetal.GESUB_CONTR_HOOFDARBEIDERS, DmfapplWnkengetal.LEERPLICHTIGE_HOOFDARBEIDERS, DmfapplWnkengetal.MINDERVALIDE_HOOFDARBEIDERS,
                    DmfapplWnkengetal.GEWONE_HOOFDARBEIDERS, DmfapplWnkengetal.ERKENDE_ONTHAALOUDERS, DmfapplWnkengetal.VASTBENOEMDE,
                    DmfapplWnkengetal.STAGIAIR_VASTBENOEM_VAK_PRIVE_DMFA);

    private static final Set<WerkgeversCategorie> CATEGORIE_IN_AANMERKING =
            ImmutableSet.of(WerkgeversCategorie.ALG_CATG_BDR_AANVL_SOC_FDS_NON_PROFIT, WerkgeversCategorie.NIET_COMMERCIEEL,
                    WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_PRIVE_ARBREG_OPENBAAR_DMFA,
                    WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_OPENB_ARBREG_OPENBAAR_DMFA,
                    WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_PRIVE_ARBREG_PRIVE_DMFA,
                    WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_OPENB_ARBREG_PRIVE_DMFA, WerkgeversCategorie.GENEESHEREN_IN_OPLEIDING);

    private static final Set<String> NACE_CODES_IN_AANMERKING =
            ImmutableSet.of("86101", "86102", "86103", "86104", "86109", "86210", "86901", "86903", "86904", "86905", "86906", "86909", "87101", "87109", "87201",
                    "87202", "87203", "87204", "87205", "87209", "87301", "87302", "87303", "87304", "87309", "87901", "87902", "87909", "88101", "88102", "88103",
                    "88104", "88109", "88911", "88912", "88919", "88991", "88992", "88993", "88994", "88996", "88999");

    private final ConstantManager constantManager;
    private final RekenTijd rekenTijd;

    public boolean check(SleutelGegevens gegevens) {
        return CATEGORIE_IN_AANMERKING.contains(gegevens.getWerkgeversCategorie()) &&
                KENGETAL_IN_AANMERKING.contains(gegevens.getWerknemersKengetal()) &&
                (isPriveKlant() || NACE_CODES_IN_AANMERKING.contains(getNaceCodeSafe(gegevens)));
    }

    private static String getNaceCodeSafe(SleutelGegevens gegevens) {
        String nace = gegevens.getNaceCode();
        return nace != null ? nace.trim() : "";
    }

    private boolean isPriveKlant() {
        Constant constantePriveKlant = constantManager.getActualConstant(Konstanten.CST_PUBLIEK_PRIVE, rekenTijd);
        return constantePriveKlant.getInteger() == 1;
    }

    public boolean isActief(RekenTijd rekenTijd, boolean dmfaAangifteAanwezig) {
        boolean isActive = constantManager.getByCodeDatum(Konstanten.CST_TOEPASSING_VERMINDERING_707, rekenTijd.eindDatum).getBoolean();
        return ACTIVITEITS_PERIODE.contains(rekenTijd.beginDatum) || (!dmfaAangifteAanwezig && isActive && ACTIVITEITS_PERIODE_OPTIONAL.contains(rekenTijd.beginDatum));
    }

    public boolean isOvernameNodig(RekenTijd rekenTijd, boolean dmfaAangifteAanwezig) {
        return dmfaAangifteAanwezig && ACTIVITEITS_PERIODE_OPTIONAL.contains(rekenTijd.beginDatum);
    }

    public LocalDateInterval getPeriodeActiefOptioneel() {
        return ACTIVITEITS_PERIODE_OPTIONAL;
    }
}
